import os

def create_files():
    files = {
        "backend/app/services/report_service.py": "from fpdf import FPDF\nfrom app.models.scan import Scan\nimport json\nimport tempfile\n\nclass ReportService:\n    @staticmethod\n    def generate_json(scan: Scan) -> dict:\n        return {\n            \"id\": scan.id,\n            \"target\": scan.target,\n            \"scan_type\": scan.scan_type,\n            \"risk_score\": scan.risk_score,\n            \"risk_level\": scan.risk_level,\n            \"confidence_score\": scan.confidence_score,\n            \"threat_intel\": [t.description for t in scan.threat_results],\n            \"recommendations\": [r.text for r in scan.recommendations],\n            \"official_url\": scan.official_websites[0].official_url if scan.official_websites else None,\n            \"created_at\": str(scan.created_at)\n        }\n\n    @staticmethod\n    def generate_markdown(scan: Scan) -> str:\n        data = ReportService.generate_json(scan)\n        md = f\"# TrustGuardAI Security Report\\n\\n\"\n        md += f\"**Target:** {data['target']} ({data['scan_type']})\\n\"\n        md += f\"**Risk Score:** {data['risk_score']}/100 | **Risk Level:** {data['risk_level']}\\n\\n\"\n        \n        md += f\"## Threat Intel Findings\\n\"\n        for flag in data['threat_intel']:\n            md += f\"- {flag}\\n\"\n            \n        md += f\"\\n## Recommendations\\n\"\n        for rec in data['recommendations']:\n            md += f\"- {rec}\\n\"\n            \n        if data['official_url']:\n            md += f\"\\n**Official Website:** {data['official_url']}\\n\"\n            \n        return md\n\n    @staticmethod\n    def generate_pdf(scan: Scan) -> str:\n        data = ReportService.generate_json(scan)\n        pdf = FPDF()\n        pdf.add_page()\n        \n        # Header\n        pdf.set_font(\"helvetica\", 'B', 24)\n        pdf.cell(0, 15, \"TrustGuardAI Security Report\", ln=True, align=\"C\")\n        pdf.set_font(\"helvetica\", '', 12)\n        pdf.cell(0, 10, f\"Scan Date: {data['created_at']}\", ln=True, align=\"C\")\n        pdf.ln(10)\n        \n        # Core Details\n        pdf.set_font(\"helvetica\", 'B', 14)\n        pdf.cell(0, 10, \"Overview\", ln=True)\n        pdf.set_font(\"helvetica\", '', 12)\n        pdf.cell(0, 10, f\"Target: {data['target']} ({data['scan_type']})\", ln=True)\n        \n        # Risk Scoring with Color\n        pdf.set_font(\"helvetica\", 'B', 12)\n        if data['risk_level'] == \"Critical\":\n            pdf.set_text_color(220, 53, 69) # Red\n        elif data['risk_level'] == \"High\":\n            pdf.set_text_color(255, 152, 0) # Orange\n        else:\n            pdf.set_text_color(40, 167, 69) # Green\n        pdf.cell(0, 10, f\"Risk Score: {data['risk_score']} / 100 ({data['risk_level']})\", ln=True)\n        pdf.set_text_color(0, 0, 0)\n        pdf.ln(5)\n        \n        # Findings\n        pdf.set_font(\"helvetica\", 'B', 14)\n        pdf.cell(0, 10, \"Technical Findings\", ln=True)\n        pdf.set_font(\"helvetica\", '', 12)\n        for flag in data['threat_intel']:\n            pdf.cell(0, 8, f\"- {flag}\", ln=True)\n        pdf.ln(5)\n        \n        # Recommendations\n        pdf.set_font(\"helvetica\", 'B', 14)\n        pdf.cell(0, 10, \"AI Recommendations\", ln=True)\n        pdf.set_font(\"helvetica\", '', 12)\n        for rec in data['recommendations']:\n            pdf.cell(0, 8, f\"- {rec}\", ln=True)\n            \n        if data['official_url']:\n            pdf.ln(5)\n            pdf.set_font(\"helvetica\", 'B', 12)\n            pdf.cell(0, 10, f\"Verified Official Website: {data['official_url']}\", ln=True)\n        \n        # Save to temp file\n        tmp_path = tempfile.mktemp(suffix=\".pdf\")\n        pdf.output(tmp_path)\n        return tmp_path\n",
        "backend/app/controllers/report_controller.py": "from fastapi import APIRouter, Depends, HTTPException\nfrom fastapi.responses import FileResponse, PlainTextResponse, JSONResponse\nfrom sqlalchemy.ext.asyncio import AsyncSession\nfrom sqlalchemy.future import select\nfrom sqlalchemy.orm import selectinload\nfrom app.database.session import get_db\nfrom app.models.scan import Scan\nfrom app.services.report_service import ReportService\nimport os\n\nrouter = APIRouter()\n\nasync def fetch_scan(scan_id: int, db: AsyncSession) -> Scan:\n    result = await db.execute(\n        select(Scan)\n        .options(selectinload(Scan.threat_results), selectinload(Scan.recommendations), selectinload(Scan.official_websites))\n        .filter(Scan.id == scan_id)\n    )\n    scan = result.scalars().first()\n    if not scan:\n        raise HTTPException(status_code=404, detail=\"Scan not found\")\n    return scan\n\n@router.get(\"/api/report/{scan_id}\")\nasync def get_report(scan_id: int, db: AsyncSession = Depends(get_db)):\n    scan = await fetch_scan(scan_id, db)\n    return ReportService.generate_json(scan)\n\n@router.get(\"/api/report/{scan_id}/json\")\nasync def get_report_json(scan_id: int, db: AsyncSession = Depends(get_db)):\n    scan = await fetch_scan(scan_id, db)\n    return JSONResponse(content=ReportService.generate_json(scan))\n\n@router.get(\"/api/report/{scan_id}/markdown\")\nasync def get_report_markdown(scan_id: int, db: AsyncSession = Depends(get_db)):\n    scan = await fetch_scan(scan_id, db)\n    md_content = ReportService.generate_markdown(scan)\n    return PlainTextResponse(content=md_content)\n\n@router.get(\"/api/report/{scan_id}/download\")\nasync def download_report_pdf(scan_id: int, db: AsyncSession = Depends(get_db)):\n    scan = await fetch_scan(scan_id, db)\n    pdf_path = ReportService.generate_pdf(scan)\n    return FileResponse(\n        path=pdf_path,\n        filename=f\"TrustGuardAI_Report_{scan_id}.pdf\",\n        media_type=\"application/pdf\"\n    )\n\n@router.get(\"/api/report/history\")\nasync def get_report_history(db: AsyncSession = Depends(get_db)):\n    # In real app, filter by current_user.id\n    result = await db.execute(select(Scan).order_by(Scan.created_at.desc()).limit(20))\n    scans = result.scalars().all()\n    return [{\"id\": s.id, \"target\": s.target, \"risk_level\": s.risk_level, \"date\": str(s.created_at)} for s in scans]\n",
        "frontend/src/pages/Results.tsx": "import React, { useEffect, useState } from 'react';\nimport { useParams } from 'react-router-dom';\nimport { motion } from 'framer-motion';\nimport { ShieldAlert, ShieldCheck, Download, FileJson, FileText, AlertTriangle, ArrowRight, Lightbulb } from 'lucide-react';\nimport api from '../utils/axios';\n\nconst Results = () => {\n  const { id } = useParams();\n  const [data, setData] = useState<any>(null);\n  const [loading, setLoading] = useState(true);\n\n  useEffect(() => {\n    const fetchReport = async () => {\n      try {\n        const res = await api.get(`/report/${id}`);\n        setData(res.data);\n      } catch (err) {\n        console.error(err);\n      } finally {\n        setLoading(false);\n      }\n    };\n    fetchReport();\n  }, [id]);\n\n  const handleDownloadPDF = async () => {\n    window.open(`http://localhost:8000/api/report/${id}/download`, '_blank');\n  };\n\n  const handleDownloadJSON = async () => {\n    window.open(`http://localhost:8000/api/report/${id}/json`, '_blank');\n  };\n\n  const handleDownloadMD = async () => {\n    window.open(`http://localhost:8000/api/report/${id}/markdown`, '_blank');\n  };\n\n  if (loading) return <div className=\"flex justify-center p-20\"><div className=\"animate-spin rounded-full h-12 w-12 border-t-2 border-primary\"></div></div>;\n  if (!data) return <div className=\"text-center p-20\">Report not found.</div>;\n\n  const isRisky = data.risk_score > 40;\n  const whyExplanations = data.threat_intel?.length > 0 \n    ? data.threat_intel.map((t: string) => `This domain triggered a security flag: ${t}`)\n    : [\"Our security checks found no immediate red flags.\"];\n\n  return (\n    <div className=\"max-w-4xl mx-auto space-y-8 pb-20\">\n      {/* Toolbar */}\n      <div className=\"flex justify-end gap-4\">\n        <button onClick={handleDownloadMD} className=\"btn-secondary flex items-center gap-2 text-sm py-2\"><FileText size={16} /> Markdown</button>\n        <button onClick={handleDownloadJSON} className=\"btn-secondary flex items-center gap-2 text-sm py-2\"><FileJson size={16} /> JSON</button>\n        <button onClick={handleDownloadPDF} className=\"btn-primary flex items-center gap-2 text-sm py-2\"><Download size={16} /> Download PDF</button>\n      </div>\n\n      {/* 1. Summary Card */}\n      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className=\"glass-panel p-8 text-center\">\n        <div className={`w-24 h-24 mx-auto rounded-full flex items-center justify-center mb-6 ${isRisky ? 'bg-danger/20 text-danger' : 'bg-success/20 text-success'}`}>\n          {isRisky ? <ShieldAlert size={48} /> : <ShieldCheck size={48} />}\n        </div>\n        <h1 className=\"text-4xl font-bold mb-2\">{data.risk_score} / 100</h1>\n        <div className={`text-xl font-medium mb-4 ${isRisky ? 'text-danger' : 'text-success'}`}>{data.risk_level} Risk</div>\n        <p className=\"text-gray-400 font-mono\">{data.target}</p>\n      </motion.div>\n\n      {/* 2. AI Recommendations */}\n      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.1 }}>\n        <h2 className=\"text-2xl font-bold mb-4 flex items-center gap-2\">\n          <ArrowRight className=\"text-primary\" /> AI Recommendations\n        </h2>\n        <div className=\"grid grid-cols-1 sm:grid-cols-2 gap-4\">\n          {data.recommendations?.map((rec: string, i: number) => (\n            <div key={i} className={`p-4 rounded-xl border ${isRisky ? 'bg-danger/5 border-danger/20' : 'bg-surface border-border'} font-medium`}>\n              {rec}\n            </div>\n          ))}\n          {data.official_url && (\n            <a href={data.official_url} target=\"_blank\" rel=\"noreferrer\" className=\"p-4 rounded-xl border bg-primary/10 border-primary/30 text-primary font-medium hover:bg-primary/20 transition\">\n              Visit Official Site: {data.official_url}\n            </a>\n          )}\n        </div>\n      </motion.div>\n\n      {/* 3. Why Section */}\n      <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.2 }} className=\"glass-panel p-8\">\n        <h2 className=\"text-2xl font-bold mb-6\">Why is this website {isRisky ? 'risky' : 'safe'}?</h2>\n        <ul className=\"space-y-4\">\n          {whyExplanations.map((exp: string, i: number) => (\n            <li key={i} className=\"flex items-start gap-3 text-gray-300\">\n              <AlertTriangle className={`shrink-0 mt-1 ${isRisky ? 'text-danger' : 'text-success'}`} size={20} />\n              <span className=\"leading-relaxed\">{exp}</span>\n            </li>\n          ))}\n        </ul>\n      </motion.div>\n\n      {/* 4. Cyber Tip Card */}\n      <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} transition={{ delay: 0.4 }} className=\"bg-gradient-to-r from-primary/20 to-blue-500/20 border border-primary/30 rounded-xl p-6 flex items-center gap-4\">\n        <div className=\"bg-primary/20 p-3 rounded-full text-primary\">\n          <Lightbulb size={24} />\n        </div>\n        <div>\n          <h4 className=\"font-bold text-white mb-1\">Cyber Safety Tip</h4>\n          <p className=\"text-gray-300 text-sm\">Always verify the URL before entering your password. Scammers often use convincing lookalikes.</p>\n        </div>\n      </motion.div>\n    </div>\n  );\n};\n\nexport default Results;\n"
    }

    for path, content in files.items():
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "w", encoding="utf-8") as f:
            f.write(content)

if __name__ == "__main__":
    create_files()
    print("Stage 12 Report Generator Scaffolded.")
